由对称性知，
$$
\begin{aligned}
& E(Y)=E(X)=\int_{-\infty}^{+\infty} \int_{-\infty}^{+\infty} x f(x, y) d y d x=\int_0^2 \int_0^2 x \cdot \frac{1}{8}(x+y) d y d x=\frac{7}{6} \\
& E\left(Y^2\right)=E\left(X^2\right)=\int_0^2 \int_0^2 x^2 \cdot \frac{1}{8}(x+y) d y d x=\frac{1}{4} \int_0^2\left(x^3+x^2\right) d x=\frac{5}{3} \\
& D(Y)=D(X)=E\left(X^2\right)-[E(X)]^2=\frac{5}{3}-\left(\frac{7}{6}\right)^2=\frac{11}{36}
\end{aligned}
$$

而
$$
\begin{aligned}
& E(X Y)=\int_{-\infty}^{+\infty} \int_{-\infty}^{+\infty} x y f(x, y) d x d y=\int_0^2 \int_0^2 x y \cdot \frac{1}{8}(x+y) d x d y=\int_0^2 \frac{1}{8}\left(\frac{8}{3} y+2 y^2\right) d y=\frac{4}{3} \\
& \operatorname{cov}(X, Y)=E(X Y)-E(X) E(Y)=\frac{4}{3}-\frac{7}{6} \times \frac{7}{6}=-\frac{1}{36} \\
& \rho_{X Y}=\frac{\operatorname{cov}(X, Y)}{\sqrt{D(X) D(Y)}}=\frac{-\frac{1}{36}}{\frac{11}{36}}=-\frac{1}{11} \\
& D(X+Y)=D(X)+D(Y)+2 \operatorname{cov}(X, Y)=\frac{11}{36}+\frac{11}{36}-2 \times \frac{1}{36}=\frac{5}{9}
\end{aligned}
$$
